// Parse Google SERP — response is in $json.data (string HTML)
const raw = $input.first().json;
let html = '';

// n8n returns HTML in .data as string
if (typeof raw.data === 'string') {
  html = raw.data;
} else if (typeof raw.body === 'string') {
  html = raw.body;
} else if (typeof raw === 'string') {
  html = raw;
} else {
  html = JSON.stringify(raw);
}

const keyword = $node.Webhook.json.body.keyword;
const analysis_id = $node.Webhook.json.body.analysis_id;
const callback_url = $node.Webhook.json.body.callback_url;

// Extract organic results using regex
const results = [];

// Pattern 1: <a href="URL">...<h3>TITLE</h3>
const linkRegex = /<a[^>]+href="(https?:\/\/[^"]+)"[^>]*>[\s\S]*?<h3[^>]*>([\s\S]*?)<\/h3>/gi;
let match;
while ((match = linkRegex.exec(html)) !== null && results.length < 10) {
  const url = match[1];
  const title = match[2].replace(/<[^>]+>/g, '').trim();
  if (!url.includes('google.') && !url.includes('gstatic.') && !url.includes('youtube.com/results') && url.startsWith('http')) {
    try {
      results.push({position: results.length + 1, url, title, domain: new URL(url).hostname});
    } catch(e) {}
  }
}

// Pattern 2 fallback: any external href with substantial text after
if (results.length === 0) {
  const altRegex = /href="(https?:\/\/(?!www\.google|gstatic|accounts\.google)[^"]{15,})"/gi;
  while ((match = altRegex.exec(html)) !== null && results.length < 10) {
    try {
      const url = match[1];
      const domain = new URL(url).hostname;
      if (!results.some(r => r.domain === domain)) {
        results.push({position: results.length + 1, url, title: domain, domain});
      }
    } catch(e) {}
  }
}

// Extract People Also Ask
const questions = [];
const paaRegex = /data-q="([^"]+)"/g;
while ((match = paaRegex.exec(html)) !== null && questions.length < 10) {
  questions.push(match[1]);
}

// If NO results at all — just send back what we have with debug
if (results.length === 0) {
  return [{json: {results: [], questions, keyword, analysis_id, callback_url, debug: 'No results found in HTML. HTML length: ' + html.length + ' chars. First 200: ' + html.substring(0, 200)}}];
}

return [{json: {results, questions, keyword, analysis_id, callback_url}}];

// Simple version: just aggregate from Parse SERP directly (skip per-page fetch for now)
// This makes it FAST and reliable — no looping through 10 pages
const meta = $input.first().json;
const results = meta.results || [];

// Build competitor list from SERP data only (no page fetching)
const competitors = results.map(r => ({
  position: r.position,
  url: r.url,
  domain: r.domain,
  title: r.title,
  word_count: 0,
  h1_count: 0,
  h2_count: 0,
  h3_count: 0,
  images: 0,
  schema_types: '',
  top_keywords: [],
  headings: {h1: [], h2: [], h3: []}
}));

return [{json: {
  analysis_id: meta.analysis_id,
  callback_url: meta.callback_url,
  avg_word_count: 0,
  avg_headings: 0,
  lsi_keywords: [],
  content_gap: [],
  questions: meta.questions || [],
  competitors: competitors
}}];
